package com.hr.soap;

import javax.jws.WebService;
import javax.xml.ws.Endpoint;
import javax.xml.bind.annotation.XmlAccessType;
import javax.xml.bind.annotation.XmlAccessorType;
import javax.xml.bind.annotation.XmlRootElement;
import java.util.ArrayList;
import java.util.List;

@WebService
@XmlRootElement(name = "hrService")
public class HrService {

    private List<Employee> employees = new ArrayList<>();

    public void addEmployee(Employee employee) {
        employees.add(employee);
    }

    public void updateSalary(String id, double salary) {
        for (Employee employee : employees) {
            if (employee.getId().equals(id)) {
                employee.setSalary(salary);
                break;
            }
        }
    }

    public void terminateEmployee(String id) {
        employees.removeIf(employee -> employee.getId().equals(id));
    }

    public String getPerformanceReview(String id, String review) {
        for (Employee employee : employees) {
            if (employee.getId().equals(id)) {
                employee.setPerformanceReview(review);
                break;
            }
        }
        return "Performance review added for employee with ID: " + id;
    }
}

